def _build_stroke_advance_table(
    advance_bytes: tuple[int, ...],
    *,
    divisor: float,
    multiplier: float,
) -> dict[int, float]:
    return {
        code: (advance_byte / divisor) * multiplier
        for code, advance_byte in zip(range(32, 256), advance_bytes, strict=True)
    }


